WITH totals AS (
  SELECT SUM(cnt) as total FROM cars
), gear_totals AS (
  SELECT gear, COUNT(*) as gear_total FROM cars GROUP BY gear
), carb_totals AS (
  SELECT carb, COUNT(*) as carb_total FROM cars GROUP BY carb
), observed AS (
  SELECT gear, carb, COUNT(*) as obs FROM cars GROUP BY gear, carb
), expected AS (
  SELECT o.gear, o.carb, (g.gear_total * c.carb_total) / t.total::DOUBLE as exp
  FROM observed o
  JOIN gear_totals g ON o.gear = g.gear
  JOIN carb_totals c ON o.carb = c.carb
  CROSS JOIN totals t
), chi AS (
  SELECT gear, carb, obs, exp, (obs - exp)*(obs - exp)/exp as chi_contrib
  FROM expected
)
SELECT SUM(chi_contrib) as chi_square, COUNT(*) as df
FROM chi;

